/**
 * Event Consumer Registry — wires handlers to the in-process event bus.
 * 
 * The event bus (event-bus.ts) has been emitting events into void.
 * This module registers actual consumers for key event types.
 * 
 * All consumers follow CQRS: they queue state mutations instead of
 * directly writing state (hooks/consumers are read-auto layer).
 */

import { eventBus, type Unsubscribe } from "./event-bus.js"
import type { ArtifactEvent } from "../schemas/events.js"
import { queueStateMutation } from "./state-mutation-queue.js"

export interface ConsumerRegistry {
  unsubscribers: Unsubscribe[]
  registered: boolean
}

/**
 * Register all event consumers.
 * Called once on plugin activation.
 * Idempotent — calling twice returns the existing registry.
 */
export function registerEventConsumers(directory: string): ConsumerRegistry

/**
 * Unregister all event consumers.
 * Called on plugin deactivation for clean shutdown.
 */
export function unregisterEventConsumers(registry: ConsumerRegistry): void
```

