### Implementation Pattern

```typescript
let activeRegistry: ConsumerRegistry | null = null

export function registerEventConsumers(_directory: string): ConsumerRegistry {
  // Idempotent — if already registered, return existing
  if (activeRegistry?.registered) {
    return activeRegistry
  }

  const unsubscribers: Unsubscribe[] = []

  // 1. memory:classified
  unsubscribers.push(
    eventBus.subscribe("memory:classified", (event: ArtifactEvent) => {
      try {
        // Track classification — state mutation handled by caller (event-handler.ts)
        // This consumer exists for secondary effects (future: auto-purge triggers)
      } catch {
        // P3: Never break event handling
      }
    })
  )

  // 2. context:consolidated  
  // 3. context:purged
  // 4. pending_change:verified

  activeRegistry = { unsubscribers, registered: true }
  return activeRegistry
}

export function unregisterEventConsumers(registry: ConsumerRegistry): void {
  for (const unsub of registry.unsubscribers) {
    try {
      unsub()
    } catch {
      // P3: Never break cleanup
    }
  }
  registry.registered = false
  registry.unsubscribers = []
  if (activeRegistry === registry) {
    activeRegistry = null
  }
}
```

### Constraints
- MUST follow CQRS: consumers queue mutations via `queueStateMutation`, never direct-save
- MUST be idempotent — calling `registerEventConsumers` twice doesn't double-subscribe
- MUST wrap every consumer in try/catch (P3: never break event handling)
- MUST NOT exceed 120 lines total
- MUST NOT import from `src/hooks/` (lib layer)
- Use double quotes for strings
- Use 2-space indentation

